using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train and save the model at startup
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" string to boolean Label column
var labelPipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapped>(
    (input, output) => output.Label = input.Churned == "Yes",
    contractName: "ChurnLabelMapping");

var mappedData = labelPipeline.Fit(dataView).Transform(dataView);
var split = mlContext.Data.TrainTestSplit(mappedData, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.Age)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.Income)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age), nameof(CustomerData.Income), "RegionEncoded", nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

// Evaluate (guard against insufficient test data)
var predictions = model.Transform(split.TestSet);
try
{
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}, Accuracy: {metrics.Accuracy:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("Model trained — test set too small for reliable metrics. Add more data for proper evaluation.");
}

// Save model for the prediction engine pool
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);

// Register pooled prediction engine (thread-safe)
builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer data");

app.MapPost("/predict", (PredictionEnginePool<CustomerInput, ChurnPrediction> pool, CustomerInput input) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
        Score = prediction.Score
    });
});

app.Run();

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
}

public class LabelMapped
{
    public bool Label { get; set; }
}

